css:
@page {
  margin: 5cm 3.6cm 2.5cm 2.3cm;
  size: A4;
  @top-right {
    content: element(infobox);
  }
  @bottom-left {
      content: element(footer-left);
  }
  @bottom-center {
      content: element(footer-center);
  }
  @bottom-right {
      content: element(footer-right);
  }
}

@page :first {
  margin: 9cm 3.6cm 2.5cm 2.3cm;
  size: A4;
  @top-left {
    vertical-align: top;
    margin-left: 2mm;
    margin-top: 58mm;
    content: element(recipient);
  }
  @top-right {
    vertical-align: top;
    margin-top: 58mm;
    content: element(infobox-first-page);
  }
    @bottom-left {
      content: element(footer-left);
  }
  @bottom-center {
      content: element(footer-center);
  }
  @bottom-right {
      content: element(footer-right);
  }
}


#recipient {
  position: running(recipient);
  width: 80mm;
  left: 0;
}

#infobox-first-page {
  position: running(infobox-first-page);
  right:0mm;
  width: 60mm;
}

#infobox {
  position: running(infobox);
  right:0mm;
  width: 60mm;
}
